import { moduleMetadata } from '@storybook/angular';
import { PfTooltipDirective } from './tooltip.directive';
import { PfButtonComponent } from '../button/button.component';
const meta = {
    title: 'Composants/Tooltip',
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Tooltip minimaliste appliqué via la directive `[pfTooltip]`. Apparition au hover + focus, disparition au mouseleave + blur + Escape. Délai par défaut 700ms.",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [PfTooltipDirective, PfButtonComponent] }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="padding: 80px; display: flex; justify-content: center;">${story.template}</div>` };
        },
    ],
};
export default meta;
export const Default = {
    render: () => ({
        template: `<pf-button variant="danger" pfTooltip="Action de suppression définitive">Supprimer</pf-button>`,
    }),
};
export const Sides = {
    render: () => ({
        template: `
      <div style="display: flex; gap: 16px; flex-wrap: wrap; justify-content: center;">
        <pf-button variant="secondary" pfTooltip="Tooltip en haut" pfTooltipSide="top">Top</pf-button>
        <pf-button variant="secondary" pfTooltip="Tooltip à droite" pfTooltipSide="right">Right</pf-button>
        <pf-button variant="secondary" pfTooltip="Tooltip en bas" pfTooltipSide="bottom">Bottom</pf-button>
        <pf-button variant="secondary" pfTooltip="Tooltip à gauche" pfTooltipSide="left">Left</pf-button>
      </div>
    `,
    }),
};
export const FastDelay = {
    render: () => ({
        template: `<pf-button pfTooltip="Apparition rapide" [pfTooltipDelay]="100">Survoler</pf-button>`,
    }),
};
